payload.query:
SELECT ?item ?itemLabel ?itemDescription ?formulaProperty ?formula ?alias ?use ?useLabel ?useDescription WHERE {
  VALUES ?formulaProperty { wdt:P2534 }
  ?item ?formulaProperty ?formula .
  VALUES ?classRoot { wd:Q36338801 wd:Q214070 }
  ?item wdt:P31/wdt:P279* ?classRoot .
  OPTIONAL { ?item skos:altLabel ?alias . FILTER(LANG(?alias) = "en") }
  OPTIONAL { ?item wdt:P366 ?use . }
  SERVICE wikibase:label {
    bd:serviceParam wikibase:language "en,mul,en".
  }
} LIMIT 50
